9	// 1 MiB cap applies to both read and write. We keep it as a byte count,
10	// not a character count, because the LLM thinks in characters but the
11	// filesystem (and any network it sits behind) thinks in bytes.
12	const MAX_FILE_BYTES = 1_048_576;
13	
14	const ReadFileInputSchema = z.object({
15	  path: z.string().min(1).max(4096),
16	});
17	
18	// I4: content is z.string() with no .max(). A Zod .max(N) on a string
19	// counts UTF-16 code units, NOT UTF-8 bytes — so '😀'.repeat(300_000) has
20	// length 600_000 (would pass .max(1_048_576)) but is 1_200_000 UTF-8 bytes.
21	// The byte cap is enforced below via Buffer.byteLength(content, 'utf8').
22	const WriteFileInputSchema = z.object({
23	  path: z.string().min(1).max(4096),
24	  content: z.string(),
25	});
