27	export function createToolFileIoPlugin(): Plugin {
28	  return {
29	    manifest: {
30	      name: PLUGIN_NAME,
31	      version: '0.0.0',
32	      registers: ['tool:execute:read_file', 'tool:execute:write_file'],
33	      calls: [],
34	      subscribes: [],
35	    },
36	    async init({ bus }) {
37	      bus.registerService(
38	        'tool:execute:read_file',
39	        PLUGIN_NAME,
40	        async (ctx, raw) => {
41	          const parsed = ReadFileInputSchema.parse(raw);
42	          const resolved = await safePath(ctx.workspace.rootPath, parsed.path);
43	          // Pre-read stat: stream a 10 GB file through readFile and we OOM
44	          // before the cap ever fires. stat first, then read only if the
45	          // size is already under the cap.
46	          const stat = await fs.stat(resolved);
47	          if (stat.size > MAX_FILE_BYTES) {
48	            throw new PluginError({
49	              code: 'invalid-payload',
50	              plugin: PLUGIN_NAME,
51	              hookName: 'tool:execute:read_file',
52	              message: `file exceeds ${MAX_FILE_BYTES} bytes (size=${stat.size})`,
53	            });
54	          }
55	          const content = await fs.readFile(resolved, 'utf8');
56	          return { path: parsed.path, content, bytes: stat.size };
57	        },
58	      );
59	
60	      bus.registerService(
61	        'tool:execute:write_file',
62	        PLUGIN_NAME,
63	        async (ctx, raw) => {
64	          const parsed = WriteFileInputSchema.parse(raw);
65	          const bytes = Buffer.byteLength(parsed.content, 'utf8');
66	          if (bytes > MAX_FILE_BYTES) {
67	            throw new PluginError({
68	              code: 'invalid-payload',
69	              plugin: PLUGIN_NAME,
70	              hookName: 'tool:execute:write_file',
71	              message: `write exceeds ${MAX_FILE_BYTES} bytes (got ${bytes})`,
72	            });
73	          }
74	          const resolved = await safePath(ctx.workspace.rootPath, parsed.path);
75	          await fs.mkdir(path.dirname(resolved), { recursive: true });
76	          await fs.writeFile(resolved, parsed.content, 'utf8');
77	          return { path: parsed.path, bytes };
78	        },
79	      );
80	    },
81	  };
