2	
3	export function makeReqId(): string {
4	  return `req-${randomBytes(6).toString('hex')}`;
5	}
6	
7	export type LogLevel = 'debug' | 'info' | 'warn' | 'error';
8	
9	export interface Logger {
10	  debug(msg: string, bindings?: Record<string, unknown>): void;
11	  info(msg: string, bindings?: Record<string, unknown>): void;
12	  warn(msg: string, bindings?: Record<string, unknown>): void;
13	  error(msg: string, bindings?: Record<string, unknown>): void;
14	  child(bindings: Record<string, unknown>): Logger;
15	}
16	
17	export interface CreateLoggerOptions {
18	  reqId: string;
19	  writer?: (line: string) => void;
20	  bindings?: Record<string, unknown>;
21	}
22	
23	// reqId/level/ts/msg are reserved log fields: they're set last on every entry
24	// so that caller-supplied bindings (including ones flowing in from plugin or
25	// model output) can't spoof them and break log correlation.
26	const RESERVED_LOG_FIELDS = ['reqId', 'level', 'ts', 'msg'] as const;
27	
28	export function createLogger(opts: CreateLoggerOptions): Logger {
29	  const writer = opts.writer ?? ((line: string) => process.stdout.write(line + '\n'));
30	  const baseBindings = stripReserved(opts.bindings);
31	
32	  const emit = (level: LogLevel, msg: string, extra?: Record<string, unknown>): void => {
33	    const entry: Record<string, unknown> = { ...baseBindings };
34	    if (extra) {
35	      for (const [k, v] of Object.entries(extra)) {
36	        if (RESERVED_LOG_FIELDS.includes(k as (typeof RESERVED_LOG_FIELDS)[number])) continue;
37	        entry[k] = v instanceof Error ? serializeError(v) : v;
38	      }
39	    }
40	    entry.level = level;
41	    entry.ts = new Date().toISOString();
42	    entry.reqId = opts.reqId;
43	    entry.msg = msg;
44	    writer(JSON.stringify(entry));
45	  };
46	
47	  return {
