1	#!/usr/bin/env node
2	import { pathToFileURL } from 'node:url';
3	import {
4	  HookBus,
5	  bootstrap,
6	  makeChatContext,
7	  registerChatLoop,
8	  type ChatOutcome,
9	  type Plugin,
10	} from '@ax/core';
11	import { llmMockPlugin } from '@ax/llm-mock';
12	import { createLlmAnthropicPlugin } from '@ax/llm-anthropic';
13	import { createStorageSqlitePlugin } from '@ax/storage-sqlite';
14	import { auditLogPlugin } from '@ax/audit-log';
15	import { createSandboxSubprocessPlugin } from '@ax/sandbox-subprocess';
16	import { createToolDispatcherPlugin } from '@ax/tool-dispatcher';
17	import { createToolBashPlugin } from '@ax/tool-bash';
18	import { createToolFileIoPlugin } from '@ax/tool-file-io';
19	import { AxConfigSchema, type AxConfig, type AxConfigInput } from './config/schema.js';
20	import { loadAxConfig } from './config/load.js';
21	
22	export interface MainOptions {
23	  message: string;
24	  /**
25	   * Library-mode config override. When set, we skip file discovery entirely
26	   * — the override is parsed (to apply defaults) and used as-is. This is the
27	   * seam tests and embedders use to avoid touching disk.
28	   */
29	  configOverride?: AxConfigInput;
30	  /** Directory to walk for `ax.config.*`. Defaults to `process.cwd()`. */
31	  cwd?: string;
32	  /**
33	   * Override the sqlite DB path from config. Exists to keep legacy `AX_DB`
34	   * env-var binary-mode working while we phase config-driven storage in.
35	   */
36	  sqlitePath?: string;
37	  /**
38	   * Override `ChatContext.workspace.rootPath`. Defaults to `cwd`, which in
39	   * turn defaults to `process.cwd()`. Tool sandboxes land inside this dir.
40	   */
41	  workspaceRoot?: string;
42	  stdout?: (line: string) => void;
43	  stderr?: (line: string) => void;
44	  /**
45	   * Test-seam ONLY. When set and `cfg.llm === 'anthropic'`, replaces the real
46	   * SDK client with the factory result — same hatch the llm-anthropic plugin
47	   * already exposes, threaded through here for library-mode tests. Lives on
48	   * `MainOptions` (not in the JSON config schema) because functions aren't
49	   * JSON-serializable and this seam must not be reachable from file-based
50	   * config. Not used in binary-mode.
51	   */
52	  anthropicClientFactory?: (apiKey: string) => {
53	    messages: { create(req: Record<string, unknown>): Promise<unknown> };
54	  };
55	}
56	
57	const DEFAULT_SQLITE_PATH = './ax-next-chat.sqlite';
58	
59	export async function main(opts: MainOptions): Promise<number> {
60	  const out = opts.stdout ?? ((line) => process.stdout.write(line + '\n'));
61	  const err = opts.stderr ?? ((line) => process.stderr.write(line + '\n'));
62	
63	  const cwd = opts.cwd ?? process.cwd();
64	  const cfg: AxConfig =
65	    opts.configOverride !== undefined
66	      ? AxConfigSchema.parse(opts.configOverride)
67	      : await loadAxConfig({ cwd });
68	
69	  const bus = new HookBus();
70	  registerChatLoop(bus);
71	
72	  const plugins: Plugin[] = [];
73	
74	  // Storage (always sqlite for now; schema gates this).
75	  plugins.push(
76	    createStorageSqlitePlugin({
77	      databasePath: opts.sqlitePath ?? DEFAULT_SQLITE_PATH,
78	    }),
79	  );
80	
81	  // Audit log is part of the canary loop.
82	  plugins.push(auditLogPlugin());
83	
84	  // Sandbox. Config only admits 'subprocess' today; the switch is future-
85	  // proofing for when alternate sandbox providers land.
86	  if (cfg.sandbox === 'subprocess') {
87	    plugins.push(createSandboxSubprocessPlugin());
88	  }
89	
90	  // Tool dispatcher is the single entry point for `tool:execute`, fanning
91	  // out to whatever tool plugins register descriptors. Always present when
92	  // we might have tools.
93	  plugins.push(createToolDispatcherPlugin());
94	  if (cfg.tools.includes('bash')) {
95	    plugins.push(createToolBashPlugin());
96	  }
97	  if (cfg.tools.includes('file-io')) {
98	    plugins.push(createToolFileIoPlugin());
99	  }
100	
101	  // LLM selection. `exactOptionalPropertyTypes` on the Anthropic plugin
102	  // config means we can't just splat through fields whose type is
103	  // `string | undefined` — we strip undefined keys first.
104	  if (cfg.llm === 'anthropic') {
105	    const a = cfg.anthropic ?? {};
106	    const anthropicCfg: {
107	      model?: string;
