22	export class PluginError extends Error {
23	  readonly code: PluginErrorCode;
24	  readonly plugin: string;
25	  readonly hookName?: string;
26	
27	  constructor(opts: PluginErrorOptions) {
28	    super(opts.message, opts.cause !== undefined ? { cause: opts.cause } : undefined);
29	    this.name = 'PluginError';
30	    this.code = opts.code;
31	    this.plugin = opts.plugin;
32	    if (opts.hookName !== undefined) this.hookName = opts.hookName;
33	  }
34	
35	  // `cause` is intentionally omitted from toJSON() to keep stack traces out of
36	  // structured logs; callers that need the cause can still read err.cause.
37	  toJSON(): Record<string, unknown> {
38	    const out: Record<string, unknown> = {
39	      name: this.name,
40	      code: this.code,
41	      plugin: this.plugin,
42	      message: this.message,
43	    };
44	    if (this.hookName !== undefined) out.hookName = this.hookName;
45	    return out;
46	  }
47	}
48	
49	export interface Rejection {
50	  readonly rejected: true;
51	  readonly reason: string;
52	  readonly source?: string;
53	}
54	
55	export function reject(opts: { reason: string; source?: string }): Rejection {
56	  const r: Rejection = opts.source !== undefined
57	    ? { rejected: true, reason: opts.reason, source: opts.source }
58	    : { rejected: true, reason: opts.reason };
59	  return r;
60	}
61	
62	export function isRejection(value: unknown): value is Rejection {
63	  return (
