        {
          sessionId: 'never-created',
          entry: { type: 'user-message', payload: { role: 'user', content: 'x' } },
        },
      );
    } catch (err) {
      caught = err;
    }
    expect(caught).toBeInstanceOf(PluginError);
    expect((caught as PluginError).code).toBe('unknown-session');
  });

